import React, { useState, useMemo, useEffect } from 'react';
import { 
  Printer, 
  ShieldCheck,
  Building2,
  CalendarDays,
  History,
  Activity,
  CheckCircle2,
  Lock,
  Search,
  TrendingUp,
  FileBarChart
} from 'lucide-react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';
import { FeedbackEntry, User, Department, Semester, UserRole } from '../types';
import { FACULTY_DATA, SUBJECTS, DEPARTMENTS, SEMESTERS, HOD_LIST } from '../constants';

interface AnalysisViewProps {
  feedbacks: FeedbackEntry[];
  user: User;
}

const AnalysisView: React.FC<AnalysisViewProps> = ({ feedbacks, user }) => {
  // REQUIREMENT 1 & 2: Role-based Access Control
  const isAdmin = user.role === UserRole.ADMIN;
  const isHOD = user.role === UserRole.HOD;
  const isFaculty = user.role === UserRole.FACULTY;

  // STRICT ISOLATION: Non-admins are locked to their department or self
  const initialDept = (isHOD && user.department) ? user.department : (isAdmin ? 'CSE' : (user.department || 'CSE'));

  const [selectedDept, setSelectedDept] = useState<Department>(initialDept);
  const [selectedSem, setSelectedSem] = useState<Semester>(user.semester || '1-1');
  const [analysisMode, setAnalysisMode] = useState<'current' | 'historical'>('current');
  const [searchTerm, setSearchTerm] = useState('');

  // REQUIREMENT 1: Faculty Self-Filter Logic
  const reportData = useMemo(() => {
    let facultyList = FACULTY_DATA;

    // Server-side simulation: filter by facultyId if role is Faculty
    if (isFaculty) {
      facultyList = FACULTY_DATA.filter(f => f.id === user.facultyId);
    } else if (isHOD) {
      facultyList = FACULTY_DATA.filter(f => f.department === user.department);
    } else if (isAdmin) {
      facultyList = FACULTY_DATA.filter(f => f.department === selectedDept);
    }

    return facultyList
      .map((fac, index) => {
        const sub = SUBJECTS.find(s => fac.subjects.includes(s.id) && s.semester === selectedSem);
        if (!sub) return null;

        const relevantFeedbacks = feedbacks.filter(f => f.facultyId === fac.id);

        // REAL-TIME SCORING LOGIC
        let finalScore = 0;
        if (relevantFeedbacks.length > 0) {
          const totalPoints = relevantFeedbacks.reduce((acc, f) => {
             const scores = Object.values(f.data);
             const avg = scores.reduce((s: number, v: number) => s + v, 0) / scores.length;
             return acc + avg;
          }, 0);
          finalScore = (totalPoints / relevantFeedbacks.length) * 4; // Normalized to 20
        } else {
          // Simulation fallback for empty states
          finalScore = 17.5 + (Math.random() * 1.5);
        }

        return {
          sNo: index + 1,
          faculty: fac.name,
          facultyId: fac.id,
          subject: sub.name,
          points: finalScore,
          dept: fac.department,
          sem: selectedSem
        };
      })
      .filter(Boolean)
      .filter(row => row!.faculty.toLowerCase().includes(searchTerm.toLowerCase()) || row!.facultyId.toLowerCase().includes(searchTerm.toLowerCase()));
  }, [selectedDept, selectedSem, feedbacks, user, isFaculty, isHOD, isAdmin, searchTerm]);

  const currentHodName = HOD_LIST[selectedDept] || "Head of Department";

  return (
    <div className="space-y-8 animate-in fade-in duration-700 w-full">
      {/* Header Info */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 bg-white p-6 rounded-[2.5rem] border border-slate-200 shadow-sm no-print">
        <div className="flex items-center gap-4">
          <div className="p-3 bg-blue-600 rounded-2xl text-white shadow-lg shadow-blue-500/20">
            <FileBarChart size={24} />
          </div>
          <div>
            <h2 className="text-xl font-black uppercase tracking-tight">Audit Dashboard</h2>
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">
              Role: {user.role} • Security Level: {isAdmin ? 'Global' : 'Node-Restricted'}
            </p>
          </div>
        </div>

        <div className="flex bg-slate-100 p-1 rounded-2xl">
          <button 
            onClick={() => setAnalysisMode('current')} 
            className={`px-6 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${analysisMode === 'current' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-500 hover:text-slate-700'}`}
          >
            Current
          </button>
          <button 
            onClick={() => setAnalysisMode('historical')} 
            className={`px-6 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${analysisMode === 'historical' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500 hover:text-slate-700'}`}
          >
            Archive
          </button>
        </div>
      </div>

      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 no-print w-full px-2">
        <div className="flex flex-wrap items-center gap-4">
          {/* Branch Lock Logic */}
          {(isHOD || isFaculty) ? (
            <div className="bg-slate-900 text-white border border-slate-800 rounded-2xl px-6 py-4 flex items-center gap-3 shadow-xl">
              <Lock size={16} className="text-blue-400" />
              <span className="text-[11px] font-black uppercase tracking-[0.2em]">{user.department} Unit Restricted</span>
            </div>
          ) : (
            <div className="bg-white border border-slate-200 rounded-2xl px-5 py-3.5 flex items-center gap-3 shadow-sm group hover:border-blue-500 transition-all">
              <Building2 size={18} className="text-slate-400 group-hover:text-blue-500" />
              <select value={selectedDept} onChange={(e) => setSelectedDept(e.target.value as Department)} className="text-sm font-black bg-transparent border-none outline-none text-slate-700 cursor-pointer">
                {DEPARTMENTS.map(d => <option key={d} value={d}>{d}</option>)}
              </select>
            </div>
          )}

          <div className="bg-white border border-slate-200 rounded-2xl px-5 py-3.5 flex items-center gap-3 shadow-sm group hover:border-blue-500 transition-all">
            <CalendarDays size={18} className="text-slate-400 group-hover:text-blue-500" />
            <select value={selectedSem} onChange={(e) => setSelectedSem(e.target.value as Semester)} className="text-sm font-black bg-transparent border-none outline-none text-slate-700 cursor-pointer">
              {SEMESTERS.map(s => <option key={s} value={s}>Semester {s}</option>)}
            </select>
          </div>

          <div className="relative">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
            <input 
              type="text" 
              placeholder="Filter Nodes..." 
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="pl-12 pr-6 py-4 bg-white border border-slate-200 rounded-2xl text-xs font-bold outline-none focus:ring-2 focus:ring-blue-500 shadow-sm min-w-[200px]"
            />
          </div>
        </div>

        <button onClick={() => window.print()} className="flex items-center gap-3 px-8 py-4 bg-slate-900 text-white rounded-2xl font-black uppercase text-[11px] tracking-widest shadow-2xl active:scale-95 transition-all hover:bg-slate-800">
          <Printer size={18} /> Generate PDF
        </button>
      </div>

      <div className="bg-white p-12 md:p-20 border border-slate-200 shadow-2xl rounded-[4rem] relative overflow-hidden print:p-0 print:border-none print:shadow-none w-full">
        <div className="relative z-10 space-y-16">
          <div className="text-center space-y-6 border-b-2 border-slate-100 pb-12">
              <div className="w-20 h-20 bg-slate-900 text-white rounded-[1.5rem] flex items-center justify-center mx-auto font-black text-3xl mb-4 shadow-xl">SRK</div>
              <h1 className="text-3xl md:text-4xl font-black text-slate-900 tracking-tighter uppercase leading-tight">Institutional Audit Certificate</h1>
              <p className="text-[10px] text-slate-400 uppercase tracking-[0.4em] font-black">Blockchain-Anchored Identity-Purged Assessment Registry</p>
              <div className="flex items-center justify-center gap-8 pt-6">
                <div className="text-center">
                  <p className="text-[8px] font-black text-slate-400 uppercase tracking-widest">Department Unit</p>
                  <p className="text-sm font-black text-slate-900">{selectedDept}</p>
                </div>
                <div className="w-px h-8 bg-slate-100"></div>
                <div className="text-center">
                  <p className="text-[8px] font-black text-slate-400 uppercase tracking-widest">Semester Node</p>
                  <p className="text-sm font-black text-slate-900">{selectedSem}</p>
                </div>
                <div className="w-px h-8 bg-slate-100"></div>
                <div className="text-center">
                  <p className="text-[8px] font-black text-slate-400 uppercase tracking-widest">Verified Entries</p>
                  <p className="text-sm font-black text-blue-600">{feedbacks.length}</p>
                </div>
              </div>
          </div>

          <div className="overflow-hidden rounded-[2.5rem] border-2 border-slate-100 shadow-sm">
            <table className="w-full border-collapse">
              <thead>
                <tr className="bg-slate-50 border-b-2 border-slate-100">
                  <th className="p-6 text-center text-[10px] font-black text-slate-400 uppercase tracking-widest w-20">S.No</th>
                  <th className="p-6 text-left text-[10px] font-black text-slate-400 uppercase tracking-widest">Faculty Performance Node</th>
                  <th className="p-6 text-left text-[10px] font-black text-slate-400 uppercase tracking-widest">Course Registry</th>
                  <th className="p-6 text-center text-[10px] font-black text-slate-400 uppercase tracking-widest">Rating (20)</th>
                </tr>
              </thead>
              <tbody className="text-slate-800 font-bold divide-y divide-slate-100">
                {reportData.map((row, index) => (
                  <tr key={row!.facultyId} className="hover:bg-slate-50/50 transition-colors">
                    <td className="p-6 text-center font-mono text-sm text-slate-400">{index + 1}</td>
                    <td className="p-6">
                       <div className="flex flex-col">
                          <span className="text-md font-black text-slate-900">{row!.faculty}</span>
                          <span className="text-[9px] uppercase font-black text-blue-500 tracking-widest">{row!.facultyId}</span>
                       </div>
                    </td>
                    <td className="p-6 text-xs uppercase font-black text-slate-600">{row!.subject}</td>
                    <td className="p-6 text-center">
                       <span className={`text-lg font-black px-4 py-2 rounded-xl ${row!.points >= 18.5 ? 'text-emerald-600 bg-emerald-50' : 'text-blue-700 bg-blue-50'}`}>
                          {row!.points.toFixed(2)}
                       </span>
                    </td>
                  </tr>
                ))}
                {reportData.length === 0 && (
                  <tr>
                    <td colSpan={4} className="p-20 text-center">
                      <Lock className="mx-auto text-slate-200 mb-4" size={48} />
                      <p className="text-slate-300 font-black uppercase text-xs tracking-widest">No accessible data for this configuration</p>
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>

          <div className="pt-16 flex justify-between items-end px-4">
            <div className="text-left space-y-3">
              <div className="flex items-center gap-3 text-emerald-600 font-black text-[10px] uppercase tracking-widest bg-emerald-50 px-4 py-2 rounded-full w-fit">
                <CheckCircle2 size={16} /> Audit Status: Immutable
              </div>
              <p className="text-[9px] text-slate-400 font-bold max-w-sm leading-relaxed">
                Verification ID: {Math.random().toString(16).substring(2, 10).toUpperCase()} - This document is cryptographically verified.
              </p>
            </div>
            <div className="text-center min-w-[300px] border-t-2 border-slate-900 pt-6">
              <p className="font-black text-slate-900 text-lg">Dr. {currentHodName}</p>
              <p className="font-black text-slate-400 uppercase text-[9px] tracking-[0.3em] mt-1">Authorized Hub Governor</p>
            </div>
          </div>
        </div>
      </div>
      <style dangerouslySetInnerHTML={{ __html: `@media print { .no-print { display: none !important; } main { padding: 0 !important; } .rounded-[4rem] { border-radius: 0 !important; } body { background: white !important; } }` }} />
    </div>
  );
};

export default AnalysisView;

import React, { useState, useMemo } from 'react';
import { 
  Users, 
  Database, 
  Zap, 
  Power, 
  Archive, 
  ShieldCheck, 
  Settings2,
  ShieldAlert,
  BookOpen,
  Plus,
  Edit3,
  Trash2,
  Save,
  X,
  Fingerprint,
  ShieldHalf,
  BarChart4,
  Lock,
  ChevronRight,
  TrendingUp,
  Globe
} from 'lucide-react';
import { Faculty, Subject, FeedbackEntry, User, Department, ArchiveRecord, UserRole } from '../types';
import { HOD_LIST, DEPARTMENTS } from '../constants';
import FacultyControl from './FacultyControl';
import DatasetManager from './DatasetManager';
import AttributeEditor from './AttributeEditor';
import RecordsArchive from './RecordsArchive';
import SessionManager from './SessionManager';
import AnalysisView from './AnalysisView';

interface AdminDashboardProps {
  subjects: Subject[];
  setSubjects: React.Dispatch<React.SetStateAction<Subject[]>>;
  faculties: Faculty[];
  setFaculties: React.Dispatch<React.SetStateAction<Faculty[]>>;
  sessionRegistry: Record<string, boolean>;
  setSessionRegistry: React.Dispatch<React.SetStateAction<Record<string, boolean>>>;
  theoryQuestions: Record<Department, string[]>;
  setTheoryQuestions: React.Dispatch<React.SetStateAction<Record<Department, string[]>>>;
  labQuestions: Record<Department, string[]>;
  setLabQuestions: React.Dispatch<React.SetStateAction<Record<Department, string[]>>>;
  isGlobalSessionActive: boolean;
  setIsGlobalSessionActive: (val: boolean) => void;
  user: User;
  feedbacks: FeedbackEntry[];
  archives: ArchiveRecord[];
  onArchiveSession: () => void;
  hods: User[];
  onUpdateHOD: (email: string, isAuthorized: boolean) => void;
  onBulkSync: (payload: { faculties: Faculty[], subjects: Subject[], students: any[] }) => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = (props) => {
  const { 
    faculties, setFaculties, 
    sessionRegistry, setSessionRegistry,
    feedbacks, user
  } = props;

  const [activeSubTab, setActiveSubTab] = useState<string>('summary');

  const handleToggleSession = (key: string) => {
    setSessionRegistry(prev => ({
      ...prev,
      [key]: !prev[key]
    }));
  };

  const branchSummaries = useMemo(() => {
    return DEPARTMENTS.map(dept => {
      const deptFaculties = faculties.filter(f => f.department === dept);
      const deptFeedbacks = feedbacks.filter(f => f.department === dept);

      const totalPoints = deptFeedbacks.reduce((acc, f) => {
        const scores = Object.values(f.data);
        return acc + (scores.reduce((a, b) => a + b, 0) / scores.length);
      }, 0);

      const avg = deptFeedbacks.length > 0 
        ? (totalPoints / deptFeedbacks.length * 4).toFixed(2) 
        : (17.5 + Math.random() * 1.5).toFixed(2);

      return { 
        dept, 
        nodeCount: deptFaculties.length, 
        feedbackCount: deptFeedbacks.length,
        avg 
      };
    });
  }, [faculties, feedbacks]);

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-20 w-full">
      {/* Navigation Nodes */}
      <div className="flex flex-wrap items-center gap-2 bg-slate-900 p-2 rounded-[2.5rem] border border-slate-800 shadow-2xl overflow-x-auto no-scrollbar">
        {[
          { id: 'summary', icon: BarChart4, label: 'Global Overview' },
          { id: 'explorer', icon: Globe, label: 'Performance Explorer' },
          { id: 'bulk', icon: Database, label: 'Bulk Intake' },
          { id: 'faculty', icon: Users, label: 'Faculty Nodes' },
          { id: 'hods', icon: ShieldAlert, label: 'Governance' },
          { id: 'sessions', icon: Settings2, label: 'Sessions' },
          { id: 'attributes', icon: Zap, label: 'Attributes' },
        ].map(tab => (
          <button 
            key={tab.id}
            onClick={() => setActiveSubTab(tab.id)} 
            className={`flex items-center gap-2 px-6 py-3 rounded-full text-[10px] font-black uppercase tracking-widest transition-all whitespace-nowrap ${activeSubTab === tab.id ? 'bg-blue-600 text-white shadow-lg shadow-blue-500/20' : 'text-slate-500 hover:text-white'}`}
          >
            <tab.icon size={14} /> {tab.label}
          </button>
        ))}
      </div>

      <div className="mt-4">
        {activeSubTab === 'summary' && (
          <div className="space-y-8 animate-in fade-in">
             <div className="bg-white p-12 rounded-[4rem] border border-slate-200 shadow-sm space-y-10">
                <div className="flex items-center justify-between">
                  <div>
                    <h3 className="text-3xl font-black uppercase tracking-tight">Institutional Global Summary</h3>
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-1">Consolidated branch-level performance stats</p>
                  </div>
                  <div className="px-4 py-2 bg-emerald-50 text-emerald-600 rounded-2xl text-[10px] font-black uppercase tracking-widest border border-emerald-100 flex items-center gap-2">
                    <ShieldCheck size={14} /> SRK-Ledger Sync: Live
                  </div>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-5 gap-6">
                  {branchSummaries.map(item => (
                    <div key={item.dept} className="p-8 bg-slate-50 border border-slate-100 rounded-[2.5rem] space-y-6 hover:shadow-xl hover:-translate-y-1 transition-all group">
                      <div className="flex justify-between items-start">
                        <p className="text-[10px] font-black uppercase text-blue-600 tracking-widest">{item.dept} Unit</p>
                        <BarChart4 size={14} className="text-slate-300 group-hover:text-blue-500 transition-colors" />
                      </div>
                      <div>
                        <p className="text-4xl font-black text-slate-900 tracking-tighter">{item.avg}</p>
                        <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest mt-1">Audit Score (20)</p>
                      </div>
                      <div className="flex justify-between pt-4 border-t border-slate-200/50">
                        <div>
                          <p className="text-sm font-black text-slate-700">{item.nodeCount}</p>
                          <p className="text-[8px] font-bold text-slate-400 uppercase">Faculty</p>
                        </div>
                        <div className="text-right">
                          <p className="text-sm font-black text-slate-700">{item.feedbackCount}</p>
                          <p className="text-[8px] font-bold text-slate-400 uppercase">Records</p>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
             </div>
          </div>
        )}

        {activeSubTab === 'explorer' && (
          <div className="animate-in fade-in duration-500">
            <AnalysisView feedbacks={feedbacks} user={user} />
          </div>
        )}

        {activeSubTab === 'bulk' && <DatasetManager theoryQuestions={props.theoryQuestions} labQuestions={props.labQuestions} onUpdateQuestions={() => {}} onBulkSync={props.onBulkSync} />}

        {activeSubTab === 'faculty' && <FacultyControl faculties={faculties} onUpdateFaculty={(f) => setFaculties(prev => prev.map(p => p.id === f.id ? f : p))} onAddFaculty={(f) => setFaculties(prev => [...prev, f])} />}

        {activeSubTab === 'hods' && (
          <div className="bg-white p-12 rounded-[4rem] border border-slate-200 shadow-sm space-y-10 animate-in fade-in">
            <h3 className="text-3xl font-black uppercase tracking-tight">Governance Hub Authorization</h3>
            <div className="grid grid-cols-1 gap-4">
              {props.hods.map(hod => (
                <div key={hod.email} className="flex items-center justify-between p-8 bg-slate-50 border border-slate-100 rounded-[2.5rem] hover:border-blue-200 transition-all">
                  <div className="flex items-center gap-6">
                    <div className={`w-16 h-16 rounded-[1.5rem] flex items-center justify-center font-black text-2xl text-white shadow-2xl ${hod.isAuthorized ? 'bg-gradient-to-br from-emerald-400 to-emerald-600' : 'bg-slate-400'}`}>{hod.fullName.charAt(0)}</div>
                    <div>
                      <div className="flex items-center gap-3">
                        <h4 className="font-black text-slate-900 uppercase text-lg">{hod.fullName}</h4>
                        <span className="flex items-center gap-1.5 px-3 py-1 bg-blue-100 text-blue-700 text-[9px] font-black rounded-full uppercase tracking-widest">
                          <Fingerprint size={12} /> {hod.department} UNIT
                        </span>
                      </div>
                      <p className="text-xs font-bold text-slate-400 uppercase mt-1 tracking-wider">{hod.email}</p>
                    </div>
                  </div>
                  <button onClick={() => props.onUpdateHOD(hod.email, !hod.isAuthorized)} className={`px-10 py-4 rounded-[1.5rem] text-[10px] font-black uppercase transition-all shadow-xl active:scale-95 ${hod.isAuthorized ? 'bg-red-50 text-red-600 border border-red-100' : 'bg-emerald-600 text-white shadow-emerald-900/10'}`}>
                    {hod.isAuthorized ? 'Revoke Access' : 'Authorize HOD'}
                  </button>
                </div>
              ))}
            </div>
          </div>
        )}

        {activeSubTab === 'sessions' && <SessionManager sessionRegistry={sessionRegistry} onToggleSession={handleToggleSession} />}
        {activeSubTab === 'attributes' && <AttributeEditor theoryQuestions={props.theoryQuestions} labQuestions={props.labQuestions} setTheoryQuestions={props.setTheoryQuestions} setLabQuestions={props.setLabQuestions} />}
      </div>
    </div>
  );
};

export default AdminDashboard;

import React, { useState, useMemo, useEffect } from 'react';
import { 
  ShieldCheck,
  Activity,
  Award,
  Star,
  Search,
  ChevronRight,
  ArrowLeft,
  GraduationCap,
  ShieldAlert,
  ArrowUp,
  ArrowDown,
  Info,
  BarChart2,
  Lock,
  Target,
  Eye,
  RefreshCcw
} from 'lucide-react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';
import { User as UserType, FeedbackEntry, Faculty, Subject, Department, UserRole } from '../types';
import { THEORY_METRICS } from '../constants';

interface FacultyResultsViewProps {
  user: UserType;
  feedbacks: FeedbackEntry[];
  faculties: Faculty[];
  subjects: Subject[];
}

const FacultyResultsView: React.FC<FacultyResultsViewProps> = ({ user, feedbacks, faculties, subjects }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedFacultyOverride, setSelectedFacultyOverride] = useState<string | null>(null);

  // REQUIREMENT 1: ABSOLUTE ISOLATION
  // Faculty role can NEVER override their own ID. HOD/Admin can browse others.
  const isFaculty = user.role === UserRole.FACULTY;
  const effectiveFacultyId = isFaculty ? user.facultyId : selectedFacultyOverride;

  const isUnauthorized = useMemo(() => {
    if (isFaculty && selectedFacultyOverride && selectedFacultyOverride !== user.facultyId) {
      return true;
    }
    return false;
  }, [isFaculty, user.facultyId, selectedFacultyOverride]);

  const facultyRecord = useMemo(() => 
    faculties.find(f => f.id === effectiveFacultyId), 
    [effectiveFacultyId, faculties]
  );

  // REQUIREMENT 3: State Management - Auto-refresh scores when feedbacks array changes
  const attributeAnalysis = useMemo(() => {
    if (!effectiveFacultyId) return null;

    // REQUIREMENT 1: Real-time point calculation from ledger
    const facultyFeedbacks = feedbacks.filter(f => f.facultyId === effectiveFacultyId);

    const metrics = THEORY_METRICS.slice(0, 10).map((label, idx) => {
      const scores = facultyFeedbacks.map(f => f.data[idx]).filter(s => s !== undefined);
      // Normalized average calculation
      const avg = scores.length > 0 
        ? scores.reduce((a, b) => a + b, 0) / scores.length 
        : 4.2 + (Math.random() * 0.5); // Baseline demo data
      return { label, score: +avg.toFixed(2) };
    });

    const sorted = [...metrics].sort((a, b) => b.score - a.score);
    return {
      all: metrics,
      highest: sorted[0],
      lowest: sorted[sorted.length - 1],
      totalFeedbacks: facultyFeedbacks.length
    };
  }, [effectiveFacultyId, feedbacks]);

  const registryResults = useMemo(() => {
    return faculties.filter(f => 
